from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a celestial body (or person) into a single,
    fluent sentence.  The function tries to use a natural phrasing for each
    predicate and joins the resulting clauses with commas and a final “and”.
    """
    if not triples:
        return ""

    # Group triples by subject for better sentence construction
    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Simple template mapping for common predicates
    def phrase(t: Triple) -> str:
        subj, pred, obj = t.subject, t.predicate, t.object

        # Normalise predicate strings (remove spaces, lower‑case)
        p = pred.strip().lower()

        # Mapping of predicate to a readable clause
        if p == "discoverer":
            return f"{subj} was discovered by {obj}"
        if p == "discovered":
            return f"{subj} was discovered on {obj}"
        if p == "epoch":
            return f"{subj} has an epoch of {obj}"
        if p == "apoapsis":
            return f"{subj} has an apoapsis of {obj}"
        if p == "periapsis":
            return f"{subj} has a periapsis of {obj}"
        if p == "orbitalperiod":
            return f"{subj} has an orbital period of {obj}"
        if p == "averagespeed":
            return f"{subj} travels at an average speed of {obj}"
        if p == "escapevelocity":
            return f"{subj} has an escape velocity of {obj}"
        if p == "mass":
            return f"{subj} has a mass of {obj}"
        if p == "density":
            return f"{subj} has a density of {obj}"
        if p == "temperature":
            return f"{subj} has a temperature of {obj}"
        if p == "maximumtemperature":
            return f"{subj} has a maximum temperature of {obj}"
        if p == "meantemperature":
            return f"{subj} has a mean temperature of {obj}"
        if p == "minimumtemperature":
            return f"{subj} has a minimum temperature of {obj}"
        if p == "rotationperiod":
            return f"{subj} has a rotation period of {obj}"
        if p == "surfacearea":
            return f"{subj} has a surface area of {obj}"
        if p == "absolutemagnitude":
            return f"{subj} has an absolute magnitude of {obj}"
        if p == "formername":
            return f"{subj} was formerly known as {obj}"
        if p == "birthdate":
            return f"{subj} was born on {obj}"
        if p == "deathdate":
            return f"{subj} died on {obj}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "deathcause":
            return f"{subj} died of {obj}"
        if p == "nationality":
            return f"{subj} has {obj} nationality"
        if p == "stateoforigin":
            return f"{subj} is from {obj}"
        if p == "almamater":
            return f"{subj} studied at {obj}"
        if p == "doctoralstudent":
            return f"{subj} supervised {obj}"
        # Fallback generic wording - use "has" for unknown predicates
        return f"{subj} has {pred} of {obj}"

    # Build clauses, trying to combine related information
    # First, collect all phrases for each subject
    subject_phrases: dict[str, list[str]] = {}
    for t in triples:
        if t.subject not in subject_phrases:
            subject_phrases[t.subject] = []
        subject_phrases[t.subject].append(phrase(t))

    # Find the main subject (the one with most triples or first in list)
    main_subject = triples[0].subject if triples else None

    # Build a list of all phrases
    all_phrases = [phrase(t) for t in triples]

    # Join clauses into a single sentence using relative clauses for better flow
    if len(all_phrases) == 1:
        sentence = all_phrases[0] + "."
    else:
        # Create a more complex sentence by joining with "which" clauses where appropriate
        # This creates better connected text like the example
        first_clause = all_phrases[0]
        remaining = all_phrases[1:]

        # Build connected sentence with relative clauses
        # Remove subject repetition from subsequent clauses to create natural flow
        if len(remaining) == 1:
            # Simple case: two clauses connected with comma and "and"
            # Remove subject from second clause if it matches the first
            second_clause = remaining[0]
            if second_clause.startswith(main_subject + " "):
                second_clause = second_clause[len(main_subject) + 1:]
            sentence = first_clause + ", and " + second_clause + "."
        else:
            # Multiple clauses - use relative pronouns for better flow
            middle_parts = []
            for i, clause in enumerate(remaining):
                # Remove subject repetition from subsequent clauses
                cleaned_clause = clause
                if cleaned_clause.startswith(main_subject + " "):
                    cleaned_clause = cleaned_clause[len(main_subject) + 1:]

                if i == len(remaining) - 1:
                    middle_parts.append("and " + cleaned_clause)
                else:
                    # Use "which" for non-first clauses about same subject
                    middle_parts.append("which " + cleaned_clause)

            sentence = first_clause + ", " + ", ".join(middle_parts) + "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

